package com.recettealarm.app;import android.app.*;import android.content.*;import android.database.*;import android.os.*;import android.widget.*;
public class DetailActivity extends Activity{long id;DB db;public void onCreate(Bundle b){super.onCreate(b);db=new DB(this);id=getIntent().getLongExtra("id",0);LinearLayout r=UI.root(this);Cursor c=db.one(id);String title="Recette";if(c.moveToFirst()){title=c.getString(c.getColumnIndexOrThrow("title"));r.addView(UI.tv(this,title,28,1));r.addView(UI.tv(this,c.getString(c.getColumnIndexOrThrow("category"))+" • "+c.getInt(c.getColumnIndexOrThrow("time"))+" min • "+c.getInt(c.getColumnIndexOrThrow("servings"))+" pers.",16,0));}c.close();Button cook=UI.btn(this,"Démarrer la Cuisine");r.addView(cook);cook.setOnClickListener(v->startActivity(new Intent(this,CookingActivity.class).putExtra("id",id)));Button edit=UI.btn(this,"Admin: Modifier / Ajouter");r.addView(edit);edit.setOnClickListener(v->startActivity(new Intent(this,EditRecipeActivity.class).putExtra("id",id)));r.addView(UI.tv(this,"Ingrédients",24,1));Cursor i=db.ingredients(id);while(i.moveToNext())r.addView(UI.card(this,"• "+i.getString(2)+"   "+i.getString(3)+" "+i.getString(4)));i.close();r.addView(UI.tv(this,"Étapes",24,1));Cursor s=db.steps(id);while(s.moveToNext())r.addView(UI.card(this,"Étape "+s.getInt(2)+" • "+s.getInt(4)+" min\n"+s.getString(3)+"\n⚠ "+s.getString(6)));s.close();}}
